sp_css.css:
* {
  -webkit-box-sizing: border-box;
  box-sizing: border-box
}

body {
  font-family: "RawlineRegular", "Raleway", Helvetica, sans-serif;
  font-weight: 400;
  font-size: 1.6rem;
  color: #555;
  line-height: $line-height-base;
  margin: 0;
  padding: 0;
  border: 0;
  letter-spacing: normal;
  vertical-align: baseline;
}

html {
  font-size: 62.5%;
  line-height: $line-height-base
}

header {
  margin: 0 auto;
}

h1, h2, h3, h4, h5, h6 {
  font-weight: 600;
  font-size: 3.6rem;
  color: #333;
  line-height: 4.4rem;
}

h2 {
  font-size: 3.2rem
}

h3 {
  font-size: 2.8rem
}

h4 {
  font-size: 2.4rem
}

h5 {
  font-size: 2rem
}

h6 {
  font-size: 1.6rem
}

.nav > li > a:hover, .nav > li > a:focus {
  color: $color-primary-darken-01;
  background-color: $color-primary-pastel-02;
}

.navbar-brand {
  padding: 0;
  margin-top: .2rem;
}

.navbar-right ul li a {
  font-family: "RawlineRegular", "Raleway", Helvetica, sans-serif;
  font-weight: 500;
  font-size: 1.4rem;
  letter-spacing: normal;
  vertical-align: baseline;
}

nav #tour-dropdown {
  display: none;
}

.navbar {
  border-bottom: 0 !important;
}

.navbar-brand img, .navbar-brand span {
  margin: 0 !important;
}

.fa {
  font-size: 16px;
}

.sp-loading-indicator {
  color: $color-primary-default;
  font-weight: 600;
  margin-top: .3rem;
}

.vce046d5773603010c94f54eb7df6a7ec .scrub-footer .sf-main {
  border-top: .1rem solid #071d41 !important;
  color: #fff !important;
  background-color: #071d41 !important;
  padding: 4.6rem 5.6rem 0 5.6rem!important;
}

.vce046d5773603010c94f54eb7df6a7ec .scrub-footer .sf-main .sf-logo-container .sf-logo {
  width: 16.5rem;
  background-size: cover;
}

.vce046d5773603010c94f54eb7df6a7ec .scrub-footer .sf-main .sf-links-container .sf-group .sf-group-title {
  color: #fff !important;
  font-weight: 700 !important;
  font-size: 1.6rem !important;
  line-height: 2.2rem !important;
  text-transform: uppercase !important;
  padding-bottom: 2.4rem !important;
}

.vce046d5773603010c94f54eb7df6a7ec .scrub-footer .sf-main .sf-links-container .sf-group .sf-link {
  padding-bottom: 0.8rem !important;
}

.vce046d5773603010c94f54eb7df6a7ec .scrub-footer .sf-main .sf-links-container .sf-group .sf-link a {
  color: #fff !important;
  font-weight: 500 !important;
  font-size: 1.4rem !important;
  line-height: 2.2rem !important;
  text-transform: none !important;
  opacity: 1 !important;
}

.vce046d5773603010c94f54eb7df6a7ec .scrub-footer .sf-main .sf-links-container .sf-group .sf-link a:hover {
  text-decoration: none;
  color: #5992ed !important;
}

.vce046d5773603010c94f54eb7df6a7ec .scrub-footer .sf-bottom, 
.vce046d5773603010c94f54eb7df6a7ec .scrub-footer .sf-bottom .sf-bottom-left .sf-bottom-link a {
  background-color: #04132a !important;
  color: #ccc !important;
  font-size: 1.3rem !important;
  font-weight: 400 !important;
}

@media only screen and (min-width: 1280px) {
  header {
    width: 1152px;
    padding-right: 0;
    padding-left: 0;
  }
}

@media only screen and (min-width: 768px) {
  header {
    padding-bottom: 0;
    padding-top: 1.4rem;
  }
}
